mapper.select:
select
e.id,e.name,e.code,e.email,e.mobile,e.id_card,e.birthday,e.sex,e.nation_code,e.political_code,e.native_place,e.graduate_school,e.major_code,e.highest_education_code,e.highest_degree_code,e.habitation,e.marital_status,e.entry_date,e.leave_date,e.dept_id,e.post_level_id,e.user_id,e.role_type,e.status,
d.name AS deptName,
epl.name AS postLevelName
from emp e
LEFT JOIN sys_dept d ON e.dept_id = d.id
LEFT JOIN emp_post_level epl ON e.post_level_id = epl.id


        and e.name like #{namePattern}


        and e.name like CONCAT('%', #{name}, '%')


        and e.code like #{codePattern}


        and e.code like CONCAT('%', #{code}, '%')


        and e.mobile like #{mobilePattern}


        and e.mobile like CONCAT('%', #{mobile}, '%')


        and e.dept_id = #{deptId}


        and e.post_level_id = #{postLevelId}


        and e.status = #{status}


order by e.id asc

select

from emp
where code = #{code}

    and id != #{id}

select

from emp


        and name like #{namePattern}


        and name like CONCAT('%', #{name}, '%')


        and code like #{codePattern}


        and code like CONCAT('%', #{code}, '%')


        and dept_id = #{deptId}


        and post_level_id = #{postLevelId}


        and status = #{status}


order by id asc
